class AllOne:

    def __init__(self):
        self.d = {}
        self.max_heap = []
        self.min_heap = []

    def inc(self, key: str) -> None:
        if key not in self.d:
            self.d[key] = 1
            self.min_heap.append((1, key))
            self.max_heap.append((-1, key))
        else:
            self.d[key] += 1
            self.max_heap.append((-self.d[key], key))
            self.min_heap.append((self.d[key], key))

    def dec(self, key: str) -> None:
        self.d[key] -= 1
        if self.d[key] == 0:
            del self.d[key]

    def getMaxKey(self) -> str:
        while self.max_heap and -self.max_heap[0][0] not in [self.d[key] for key in self.d]:
            heapq.heappop(self.max_heap)
        return self.max_heap[0][1] if self.max_heap else ""

    def getMinKey(self) -> str:
        while self.min_heap and self.min_heap[0][0] not in [self.d[key] for key in self.d]:
            heapq.heappop(self.min_heap)
        return self.min_heap[0][1] if self.min_heap else ""
